module counter_64bit (
    input wire clk,
    input wire reset,
    output reg [63:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 64'b0;
        end else begin
            count <= count + 1;
        end
    end
endmodule
